/**
 * Custom hook for PaymentMethods account management
 */

import { useState, useEffect, useCallback } from 'react';
import { settlementAccountService } from '@/features/settings/services';
import { filterAndMapAccounts } from '@/features/payment-methods/utils/accountMappers.js';
import { INITIAL_MOBILE_MONEY_FORM, INITIAL_BANK_ACCOUNT_FORM } from '@/features/payment-methods/constants';
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

export const usePaymentMethods = (showError, success, userType = 'business_contact') => {
  const [mobileMoneyAccounts, setMobileMoneyAccounts] = useState([]);
  const [bankAccounts, setBankAccounts] = useState([]);

  // Form states
  const [isAddingMobileMoney, setIsAddingMobileMoney] = useState(false);
  const [isAddingBankAccount, setIsAddingBankAccount] = useState(false);
  const [editingAccount, setEditingAccount] = useState(null); // null, 'momo', or 'bank'
  const [editingAccountId, setEditingAccountId] = useState(null);

  const [newMobileMoney, setNewMobileMoney] = useState(INITIAL_MOBILE_MONEY_FORM);
  const [newBankAccount, setNewBankAccount] = useState(INITIAL_BANK_ACCOUNT_FORM);

  // Use React Query to load accounts with automatic caching and refetching
  // Fixed endpoint to match Postman collection: /api/auth/profile/settlement-account (not /auth/settlement-accounts)
  const { data: accountsData, isLoading, refetch: refetchAccounts } = useQuery({
    queryKey: queryKeys.paymentMethods.all(),
    endpoint: '/api/auth/profile/settlement-account',
    enabled: true,
    staleTime: 5 * 60 * 1000, // 5 minutes - increased for better caching
    cacheTime: 10 * 60 * 1000, // 10 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      // Handle different response structures
      let accounts = [];
      if (Array.isArray(response)) {
        accounts = response;
      } else if (response?.data) {
        accounts = Array.isArray(response.data) ? response.data : [response.data];
      } else if (response?.account || response?.accounts) {
        accounts = Array.isArray(response.accounts) ? response.accounts : [response.account];
      }
      return filterAndMapAccounts(accounts);
    },
    onError: (error) => {
      logger.error('Failed to load accounts', { error });
      showError(error?.message || 'Failed to load payment methods');
    },
  });

  // Update state when accounts data changes
  useEffect(() => {
    if (accountsData) {
      setBankAccounts(accountsData.banks || []);
      setMobileMoneyAccounts(accountsData.momos || []);
    }
  }, [accountsData]);

  // Use React Query mutation for adding/updating mobile money account
  const addMobileMoneyMutation = useMutation({
    mutationFn: async ({ isEdit, accountId, payload }) => {
      if (isEdit && accountId) {
        return await settlementAccountService.updateSettlementAccount(
          accountId,
          payload,
          'momo',
          userType
        );
      } else {
        return await settlementAccountService.addMomoAccount(payload, userType);
      }
    },
    invalidateQueries: [
      queryKeys.paymentMethods.all(),
      queryKeys.settings.bankAccounts(),
      queryKeys.settings.mobileMoneyAccounts(),
    ],
    onSuccess: (_, variables) => {
      success(variables.isEdit
        ? 'Mobile money account updated successfully'
        : 'Mobile money account added successfully'
      );
      handleCancelAddMobileMoney();
    },
    onError: (error) => {
      showError(error?.message || 'Failed to save mobile money account');
    },
  });

  const handleAddMobileMoney = useCallback(async () => {
    // Resolve account name from user data if not provided
    let resolvedAccountName = newMobileMoney.accountName || '';
    if (!resolvedAccountName) {
      try {
        const { tokenService } = await import('@/features/auth/services/tokenService.js');
        const user = tokenService.getUserData();
        resolvedAccountName = user?.full_name || user?.name || user?.trading_name || user?.business_name || '';
      } catch (_e) { }
    }

    if (!newMobileMoney.provider || !newMobileMoney.phoneNumber.trim() || !resolvedAccountName) {
      showError('Please fill in Mobile Money Provider, Phone Number, and Account Name');
      return;
    }

    const isEdit = editingAccount === 'momo' && editingAccountId;
    const payload = isEdit
      ? {
        account_name: resolvedAccountName,
        account_number: newMobileMoney.phoneNumber,
        network: newMobileMoney.provider.toUpperCase(),
        currency: newMobileMoney.currency || 'GHS',
      }
      : {
        network: newMobileMoney.provider.toUpperCase(),
        accountNumber: newMobileMoney.phoneNumber,
        accountName: resolvedAccountName,
        currency: newMobileMoney.currency || 'GHS',
      };

    addMobileMoneyMutation.mutate({
      isEdit,
      accountId: editingAccountId,
      payload,
    });
  }, [newMobileMoney, editingAccount, editingAccountId, addMobileMoneyMutation, showError, userType]);

  // Use React Query mutation for adding/updating bank account
  const addBankAccountMutation = useMutation({
    mutationFn: async ({ isEdit, accountId, payload }) => {
      if (isEdit && accountId) {
        return await settlementAccountService.updateSettlementAccount(
          accountId,
          payload,
          'bank',
          userType
        );
      } else {
        return await settlementAccountService.addBankAccount(payload, userType);
      }
    },
    invalidateQueries: [
      queryKeys.paymentMethods.all(),
      queryKeys.settings.bankAccounts(),
      queryKeys.settings.mobileMoneyAccounts(),
    ],
    onSuccess: (_, variables) => {
      success(variables.isEdit
        ? 'Bank account updated successfully'
        : 'Bank account added successfully'
      );
      handleCancelAddBankAccount();
    },
    onError: (error) => {
      showError(error?.message || 'Failed to save bank account');
    },
  });

  const handleAddBankAccount = useCallback(async () => {
    // Resolve holder name from user data if not provided
    let resolvedHolderName = newBankAccount.accountHolderName;
    if (!resolvedHolderName) {
      try {
        const { tokenService } = await import('@/features/auth/services/tokenService.js');
        const user = tokenService.getUserData();
        resolvedHolderName = user?.full_name || user?.name || user?.trading_name || user?.business_name || '';
      } catch (_e) { }
    }

    if (!newBankAccount.bankName ||
      !newBankAccount.accountNumber ||
      !resolvedHolderName) {
      showError('Please fill in Bank Name, Account Number and Account Holder Name');
      return;
    }

    const isEdit = editingAccount === 'bank' && editingAccountId;
    const payload = isEdit
      ? {
        account_holder_name: resolvedHolderName,
        bank_name: newBankAccount.bankName,
        account_number: newBankAccount.accountNumber,
        account_category: newBankAccount.accountType,
        branch: newBankAccount.branch || '',
        swift_bic: newBankAccount.swiftCode || '',
        currency: newBankAccount.currency || 'GHS',
      }
      : {
        bankName: newBankAccount.bankName,
        accountNumber: newBankAccount.accountNumber,
        accountHolderName: resolvedHolderName,
      };

    addBankAccountMutation.mutate({
      isEdit,
      accountId: editingAccountId,
      payload,
    });
  }, [newBankAccount, editingAccount, editingAccountId, addBankAccountMutation, showError, userType]);

  // Use React Query mutation for deleting account
  const deleteAccountMutation = useMutation({
    mutationFn: async ({ accountId }) => {
      return await settlementAccountService.deleteSettlementAccount(accountId);
    },
    invalidateQueries: [
      queryKeys.paymentMethods.all(),
      queryKeys.settings.bankAccounts(),
      queryKeys.settings.mobileMoneyAccounts(),
    ],
    onSuccess: (_, variables) => {
      success(`${variables.accountType === 'momo' ? 'Mobile money' : 'Bank'} account deleted successfully`);
    },
    onError: (error, variables) => {
      showError(error?.message || `Failed to delete ${variables.accountType} account`);
    },
  });

  const handleDeleteAccount = useCallback(async (accountId, accountType) => {
    if (!window.confirm(`Are you sure you want to delete this ${accountType} account?`)) {
      return;
    }
    deleteAccountMutation.mutate({ accountId, accountType });
  }, [deleteAccountMutation]);

  // Set Default Account (not implemented in service - keeping for compatibility)
  const handleSetDefaultMobileMoney = useCallback(async (accountId) => {
    // TODO: Implement setDefaultSettlementAccount in service if needed
    logger.warn('setDefaultSettlementAccount not implemented');
  }, []);

  const handleSetDefaultBankAccount = useCallback(async (accountId) => {
    // TODO: Implement setDefaultSettlementAccount in service if needed
    logger.warn('setDefaultSettlementAccount not implemented');
  }, []);

  // Edit handlers
  const handleEditMobileMoney = useCallback((account) => {
    setNewMobileMoney({
      provider: account.provider.toLowerCase(),
      phoneNumber: account.phoneNumber,
      accountName: account.accountName,
      currency: account.currency || 'GHS',
    });
    setEditingAccount('momo');
    setEditingAccountId(account.id);
    setIsAddingMobileMoney(true);
  }, []);

  const handleEditBankAccount = useCallback((account) => {
    // Dynamically import constants to find the bank code match
    import('@/features/payment-methods/constants').then(({ GHANA_BANKS }) => {
      const matchedBank = GHANA_BANKS.find(b => 
        b.label.toLowerCase().includes(account.bankName?.toLowerCase()) || 
        account.bankName?.toLowerCase().includes(b.label.toLowerCase())
      );

      setNewBankAccount({
        bankName: account.bankName,
        bankCode: matchedBank?.value || '', 
        accountNumber: account.rawAccountNumber || account.accountNumber.replace(/\*+/g, ''),
        accountType: account.accountType,
        accountHolderName: account.accountHolderName,
        currency: account.currency || 'GHS',
        branch: account.branch || '',
        swiftCode: account.swiftCode || '',
      });
      setEditingAccount('bank');
      setEditingAccountId(account.id);
      setIsAddingBankAccount(true);
    });
  }, []);

  // Cancel handlers
  const handleCancelAddMobileMoney = useCallback(() => {
    setNewMobileMoney(INITIAL_MOBILE_MONEY_FORM);
    setIsAddingMobileMoney(false);
    setEditingAccount(null);
    setEditingAccountId(null);
  }, []);

  const handleCancelAddBankAccount = useCallback(() => {
    setNewBankAccount(INITIAL_BANK_ACCOUNT_FORM);
    setIsAddingBankAccount(false);
    setEditingAccount(null);
    setEditingAccountId(null);
  }, []);

  const handleCancelEdit = useCallback(() => {
    handleCancelAddMobileMoney();
    handleCancelAddBankAccount();
  }, [handleCancelAddMobileMoney, handleCancelAddBankAccount]);

  return {
    // State
    mobileMoneyAccounts,
    bankAccounts,
    isLoading: isLoading || addMobileMoneyMutation.isPending || addBankAccountMutation.isPending || deleteAccountMutation.isPending,
    isAddingMobileMoney,
    isAddingBankAccount,
    editingAccount,
    editingAccountId,
    newMobileMoney,
    newBankAccount,

    // Setters
    setNewMobileMoney,
    setNewBankAccount,
    setIsAddingMobileMoney,
    setIsAddingBankAccount,

    // Actions
    loadAccounts: refetchAccounts,
    handleAddMobileMoney,
    handleAddBankAccount,
    handleDeleteAccount,
    handleSetDefaultMobileMoney,
    handleSetDefaultBankAccount,
    handleEditMobileMoney,
    handleEditBankAccount,
    handleCancelAddMobileMoney,
    handleCancelAddBankAccount,
    handleCancelEdit,
  };
};





