/**
 * Bank Account Form Component
 * Shared form for adding/editing bank accounts
 */

import React, { useState } from 'react';
import { useToast } from '@/app/providers/ToastContext.jsx';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { GHANA_BANKS, ACCOUNT_TYPES } from '@/features/payment-methods/constants';
import { disbursementService } from '@/features/disbursements/services';

const BankAccountForm = ({
  formData,
  onChange,
  onSubmit,
  onCancel,
  isEditing,
  isLoading = false,
}) => {
  const { success, error } = useToast();
  const [isValidatingAccount, setIsValidatingAccount] = useState(false);
  const [accountDetailsFetched, setAccountDetailsFetched] = useState(false);

  const handleBankChange = (e) => {
    const selectedBank = GHANA_BANKS.find(bank => bank.value === e.target.value);
    onChange({
      ...formData,
      bankCode: selectedBank?.value || '',
      bankName: selectedBank?.label || '',
      accountHolderName: '',
    });
    setAccountDetailsFetched(false);
  };

  const handleAccountNumberChange = (value) => {
    onChange({
      ...formData,
      accountNumber: value,
      accountHolderName: '',
    });
    setAccountDetailsFetched(false);
  };

  const canFetchAccountDetails = () => {
    if (!formData.accountNumber || !formData.accountNumber.trim() || !formData.bankCode) {
      return false;
    }
    return true;
  };

  const handleFetchAccountDetails = async () => {
    if (!formData.bankCode) {
      error('Please select a bank');
      return;
    }
    if (!formData.accountNumber || !formData.accountNumber.trim()) {
      error('Please enter an account number');
      return;
    }

    setIsValidatingAccount(true);
    try {
      const response = await disbursementService.verifyBankIdentity({
        accountNumber: formData.accountNumber.trim(),
        bankCode: formData.bankCode,
      });

      if (response?.status === 'success') {
        const fullName = response.name || '';
        
        // Update state first
        setAccountDetailsFetched(true);
        onChange({
          ...formData,
          bankName: response.bank_name || formData.bankName,
          accountHolderName: fullName,
        });
        
        // Then show success message
        success('Account details fetched successfully');
        return;
      }

      error('Unable to fetch account details');
    } catch (fetchError) {
      error(fetchError?.message || 'Unable to fetch account details');
    } finally {
      setIsValidatingAccount(false);
    }
  };

  return (
    <div
      style={{
        padding: '20px',
        border: '1px solid var(--border-primary)',
        borderRadius: '8px',
        backgroundColor: 'var(--bg-tertiary)',
      }}
    >
      <h4 style={{ marginTop: 0, marginBottom: 20, color: 'var(--text-primary)' }}>
        {isEditing ? 'Edit Bank Account' : 'Add Bank Account'}
      </h4>
      <div style={{ display: 'grid', gap: '16px', maxWidth: '100%' }}>
        {/* Bank Selection */}
        <div>
          <label
            style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
            }}
          >
            Select Bank
          </label>
          <CustomSelect
            name="bankCode"
            value={formData.bankCode || ''}
            onChange={handleBankChange}
            options={GHANA_BANKS.map(bank => ({
              value: bank.value,
              label: (
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <div style={{
                    width: '24px',
                    height: '24px',
                    borderRadius: '4px',
                    overflow: 'hidden',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    backgroundColor: '#fff',
                    border: '1px solid var(--border-secondary)',
                    flexShrink: 0
                  }}>
                    <img
                      src={`/banklogos/${bank.value.toLowerCase()}.svg`}
                      alt={bank.label}
                      style={{
                        width: '100%',
                        height: '100%',
                        objectFit: 'contain'
                      }}
                      onError={(e) => {
                        const currentSrc = e.target.src;
                        if (currentSrc.endsWith('.svg')) {
                          e.target.src = currentSrc.replace('.svg', '.png');
                        } else if (currentSrc.endsWith('.png')) {
                          e.target.src = currentSrc.replace('.png', '.ico');
                        } else {
                          e.target.style.display = 'none';
                          const parent = e.target.parentElement;
                          if (parent) {
                            parent.innerHTML = '<span class="material-symbols-outlined" style="font-size: 16px; color: var(--text-muted)">account_balance</span>';
                          }
                        }
                      }}
                    />
                  </div>
                  <span>{bank.label}</span>
                </div>
              )
            }))}
            placeholder="Choose a bank"
            showCheckmark={false}
          />
        </div>

        {/* Account Number */}
        <div>
          <label
            style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
            }}
          >
            Account Number
          </label>
          <input
            type="text"
            placeholder="Enter account number"
            value={formData.accountNumber}
            onChange={(e) => handleAccountNumberChange(e.target.value)}
            style={{
              width: '100%',
              padding: '10px',
              border: '1px solid var(--border-secondary)',
              borderRadius: '6px',
              fontSize: '14px',
              backgroundColor: 'var(--bg-input)',
              color: 'var(--text-primary)',
            }}
          />
        </div>

        {/* Fetch Account Details Button */}
        <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
          <button
            type="button"
            onClick={handleFetchAccountDetails}
            disabled={isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()}
            style={{
              padding: '10px 16px',
              borderRadius: '6px',
              border: '1px solid var(--border-secondary)',
              backgroundColor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'var(--bg-input)'
                : '#004895',
              color: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'var(--text-muted)'
                : 'white',
              cursor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'not-allowed'
                : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
            }}
          >
            {isValidatingAccount ? 'Fetching...' : accountDetailsFetched ? 'Details Fetched' : 'Fetch Account Details'}
          </button>
          {!canFetchAccountDetails() && !isValidatingAccount && !accountDetailsFetched && (
            <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
              Enter bank and account number to fetch
            </span>
          )}
        </div>

        {/* Show Verification Details only when details have been FRESHLY fetched */}
        {accountDetailsFetched && (
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
            <div>
              <label
                style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                }}
              >
                Bank Name
              </label>
              <input
                type="text"
                placeholder="Bank name"
                value={formData.bankName || ''}
                readOnly
                disabled
                style={{
                  width: '100%',
                  padding: '10px',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '6px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-tertiary)',
                  color: 'var(--text-primary)',
                }}
              />
            </div>
            <div>
              <label
                style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                }}
              >
                Account Holder Name
              </label>
              <input
                type="text"
                placeholder="Account holder name"
                value={formData.accountHolderName || ''}
                readOnly
                disabled
                style={{
                  width: '100%',
                  padding: '10px',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '6px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-tertiary)',
                  color: 'var(--text-primary)',
                }}
              />
            </div>
          </div>
        )}

        {/* Account Type, Branch, Swift Code - Always visible if editing or details are fetched */}
        {(accountDetailsFetched || isEditing) && (
          <div style={{ display: 'grid', gap: '16px' }}>
            <div>
              <label
                style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: 'var(--text-primary)',
                }}
              >
                Account Type
              </label>
              <select
                value={formData.accountType}
                onChange={(e) => onChange({ ...formData, accountType: e.target.value })}
                style={{
                  width: '100%',
                  padding: '10px',
                  border: '1px solid var(--border-secondary)',
                  borderRadius: '6px',
                  fontSize: '14px',
                  backgroundColor: 'var(--bg-input)',
                  color: 'var(--text-primary)',
                }}
              >
                {ACCOUNT_TYPES.map((type) => (
                  <option key={type.value} value={type.value}>
                    {type.label}
                  </option>
                ))}
              </select>
            </div>

            {/* Branch and Swift Code - Always editable when details are present */}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
              <div>
                <label
                  style={{
                    display: 'block',
                    marginBottom: '8px',
                    color: 'var(--text-primary)',
                  }}
                >
                  Branch (Optional)
                </label>
                <input
                  type="text"
                  placeholder="Enter branch name"
                  value={formData.branch || ''}
                  onChange={(e) => onChange({ ...formData, branch: e.target.value })}
                  style={{
                    width: '100%',
                    padding: '10px',
                    border: '1px solid var(--border-secondary)',
                    borderRadius: '6px',
                    fontSize: '14px',
                    backgroundColor: 'var(--bg-input)',
                    color: 'var(--text-primary)',
                  }}
                />
              </div>
              <div>
                <label
                  style={{
                    display: 'block',
                    marginBottom: '8px',
                    color: 'var(--text-primary)',
                  }}
                >
                  Swift Code (Optional)
                </label>
                <input
                  type="text"
                  placeholder="Enter SWIFT/BIC code"
                  value={formData.swiftCode || ''}
                  onChange={(e) => onChange({ ...formData, swiftCode: e.target.value })}
                  style={{
                    width: '100%',
                    padding: '10px',
                    border: '1px solid var(--border-secondary)',
                    borderRadius: '6px',
                    fontSize: '14px',
                    backgroundColor: 'var(--bg-input)',
                    color: 'var(--text-primary)',
                  }}
                />
              </div>
            </div>
          </div>
        )}

        {/* Action Buttons */}
        <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
          <button
            onClick={onSubmit}
            disabled={isLoading}
            style={{
              padding: '10px 20px',
              backgroundColor: '#004895',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
              opacity: isLoading ? 0.6 : 1,
            }}
          >
            {isLoading ? 'Saving...' : (isEditing ? 'Update Account' : 'Add Account')}
          </button>
          <button
            onClick={onCancel}
            disabled={isLoading}
            style={{
              padding: '10px 20px',
              backgroundColor: 'transparent',
              color: '#6b7280',
              border: '1px solid #d1d5db',
              borderRadius: '6px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
            }}
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default BankAccountForm;





