/**
 * Custom hook for Settlement Configuration
 */

import { useState, useEffect, useCallback } from 'react';
import { settlementAccountService } from '@/features/settings/services';
import {
  mapSettlementModeResponse,
  mapSettlementConfigToBackend,
  getDefaultSettlementConfig
} from '@/features/payment-methods/utils/settlementHelpers.js';
import { INITIAL_SETTLEMENT_CONFIG } from '@/features/payment-methods/constants';
import { useMutation, useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

export const useSettlementConfig = (showError, success) => {
  const [settlementConfig, setSettlementConfig] = useState(INITIAL_SETTLEMENT_CONFIG);

  // Use React Query to load settlement configuration
  const { data: configData, isLoading: isLoadingConfig } = useQuery({
    queryKey: queryKeys.paymentMethods.settlementConfig(),
    endpoint: '/api/auth/profile/settlement-mode',
    enabled: true,
    staleTime: 2 * 60 * 1000, // 2 minutes
    refetchOnWindowFocus: false, // Reduced from true to prevent excessive refetches
    select: (response) => {
      return mapSettlementModeResponse(response);
    },
    onError: (error) => {
      logger.error('Failed to load settlement config', { error });
      // Don't show error on initial load, might not be set yet
    },
  });

  // Update state when config data changes
  useEffect(() => {
    if (configData) {
      setSettlementConfig(prev => ({
        ...prev,
        ...configData,
      }));
    }
  }, [configData]);

  // Use React Query mutation for saving settlement configuration
  const saveSettlementMutation = useMutation({
    mutationFn: async (backendConfig) => {
      return await settlementAccountService.setSettlementMode(backendConfig);
    },
    invalidateQueries: [
      queryKeys.paymentMethods.settlementConfig(),
      queryKeys.paymentMethods.all(),
    ],
    onSuccess: (_, newConfig) => {
      setSettlementConfig(newConfig);
      success('Settlement configuration saved successfully');
    },
    onError: (error) => {
      logger.error('Failed to save settlement config', { error });
      showError(error?.message || 'Failed to save settlement configuration');
    },
  });

  // Use React Query mutation for resetting settlement configuration
  const resetSettlementMutation = useMutation({
    mutationFn: async (defaultConfig) => {
      return await settlementAccountService.setSettlementMode(defaultConfig);
    },
    invalidateQueries: [
      queryKeys.paymentMethods.settlementConfig(),
      queryKeys.paymentMethods.all(),
    ],
    onSuccess: () => {
      const defaultMappedConfig = getDefaultSettlementConfig();
      setSettlementConfig(prev => ({
        ...prev,
        ...defaultMappedConfig,
      }));
      success('Settlement mode reset to default successfully');
    },
    onError: (error) => {
      logger.error('Failed to reset settlement config', { error });
      showError(error?.message || 'Failed to reset settlement configuration');
    },
  });

  const handleSaveSettlementMode = useCallback(async (newConfig) => {
    const backendConfig = mapSettlementConfigToBackend(newConfig);
    saveSettlementMutation.mutate(backendConfig, {
      onSuccess: () => {
        setSettlementConfig(newConfig);
      },
    });
  }, [saveSettlementMutation]);

  const handleResetSettlementMode = useCallback(async () => {
    const defaultConfig = {
      mode: 'INSTANT',
      other_details: 'Manual',
    };
    resetSettlementMutation.mutate(defaultConfig);
  }, [resetSettlementMutation]);

  return {
    settlementConfig,
    setSettlementConfig,
    isLoading: isLoadingConfig || saveSettlementMutation.isPending || resetSettlementMutation.isPending,
    loadSettlementConfig: () => { }, // No longer needed, React Query handles it
    handleSaveSettlementMode,
    handleResetSettlementMode,
  };
};





