/**
 * Settlement configuration helpers
 * Maps backend settlement mode responses to frontend state
 */

/**
 * Map backend settlement mode response to frontend state
 * @param {object} modeResponse - Response from settlement mode API
 * @returns {object} Mapped settlement configuration
 */
export const mapSettlementModeResponse = (modeResponse) => {
  if (!modeResponse) {return {};}

  // Extract the actual settlement data from the API response
  let settlementData = null;

  if (modeResponse.data) {
    // If data is an array, take the first item (or null if empty)
    if (Array.isArray(modeResponse.data)) {
      settlementData = modeResponse.data.length > 0 ? modeResponse.data[0] : null;
    } else {
      // If data is an object, use it directly
      settlementData = modeResponse.data;
    }
  } else {
    // Fallback to using the response directly (legacy format)
    settlementData = modeResponse;
  }

  if (!settlementData) {return {};}

  let settlementMode = 'instant';
  let instantType = 'manual';
  let cycleSchedule = 'daily';
  let thresholdAmount = '';
  let thresholdCurrency = 'GHS';

  if (settlementData.mode) {
    switch (settlementData.mode.toUpperCase()) {
      case 'INSTANT':
        settlementMode = 'instant';
        break;
      case 'T1':
        settlementMode = 't1';
        break;
      case 'FIXED_CYCLE':
        settlementMode = 'fixed_cycle';
        break;
      case 'ACCUMULATED_THRESHOLD':
        settlementMode = 'accumulated_threshold';
        break;
      default:
        settlementMode = 'instant';
    }
  }

  if (settlementData.other_details) {
    const otherDetails = settlementData.other_details;

    // For INSTANT mode
    if (settlementMode === 'instant') {
      if (typeof otherDetails === 'string') {
        instantType = otherDetails.toLowerCase() === 'auto' ? 'auto' : 'manual';
      } else if (otherDetails.instant_type) {
        instantType = otherDetails.instant_type.toLowerCase();
      }
    }

    // For FIXED_CYCLE mode
    if (settlementMode === 'fixed_cycle') {
      if (typeof otherDetails === 'string') {
        const schedule = otherDetails.toLowerCase();
        if (['daily', 'weekly', 'monthly'].includes(schedule)) {
          cycleSchedule = schedule;
        }
      } else if (otherDetails.schedule) {
        cycleSchedule = otherDetails.schedule.toLowerCase();
      }
    }

    // For ACCUMULATED_THRESHOLD mode
    if (settlementMode === 'accumulated_threshold') {
      if (typeof otherDetails === 'string') {
        // Try to parse threshold from string
        const thresholdMatch = otherDetails.match(/(\d+(?:\.\d+)?)\s*([A-Z]{3})/i);
        if (thresholdMatch) {
          thresholdAmount = thresholdMatch[1];
          thresholdCurrency = thresholdMatch[2].toUpperCase();
        }
      } else if (otherDetails.threshold_amount) {
        thresholdAmount = String(otherDetails.threshold_amount);
        thresholdCurrency = otherDetails.threshold_currency || 'GHS';
      }
    }
  }

  return {
    settlementMode,
    instantType,
    cycleSchedule,
    thresholdAmount,
    thresholdCurrency,
    defaultMomoAccountId: settlementData.default_momo_account_id || settlementData.defaultMomoAccountId || '',
    defaultBankAccountId: settlementData.default_bank_account_id || settlementData.defaultBankAccountId || '',
  };
};

/**
 * Map frontend settlement config to backend format
 * @param {object} config - Frontend settlement configuration
 * @returns {object} Backend format settlement configuration
 */
export const mapSettlementConfigToBackend = (config) => {
  const backendConfig = {
    mode: config.settlementMode.toUpperCase(),
  };

  // Build other_details based on settlement mode
  if (config.settlementMode === 'instant') {
    backendConfig.other_details = config.instantType === 'auto' ? 'Auto' : 'Manual';
  } else if (config.settlementMode === 'fixed_cycle') {
    backendConfig.other_details = config.cycleSchedule.charAt(0).toUpperCase() + config.cycleSchedule.slice(1);
  } else if (config.settlementMode === 'accumulated_threshold') {
    backendConfig.other_details = `${config.thresholdAmount} ${config.thresholdCurrency}`;
  }

  // Add default account IDs if set
  if (config.defaultMomoAccountId) {
    backendConfig.default_momo_account_id = config.defaultMomoAccountId;
  }
  if (config.defaultBankAccountId) {
    backendConfig.default_bank_account_id = config.defaultBankAccountId;
  }

  return backendConfig;
};

/**
 * Get default settlement configuration
 * @returns {object} Default settlement config
 */
export const getDefaultSettlementConfig = () => {
  return {
    settlementMode: 'instant',
    instantType: 'manual',
    cycleSchedule: 'daily',
    thresholdAmount: '',
    thresholdCurrency: 'GHS',
    defaultMomoAccountId: '',
    defaultBankAccountId: '',
  };
};





