/**
 * Confirm Disable 2FA Modal Component
 * 
 * Custom confirmation modal for disabling two-factor authentication.
 * Replaces browser's default confirm dialog with a styled modal.
 */

import React from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';

const ConfirmDisable2FAModal = ({ open, onClose, onConfirm }) => {
  const { t } = useTranslation();

  if (!open) {return null;}

  const handleOverlayClick = (e) => {
    // Only close if clicking directly on the overlay, not on the modal content
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  const handleModalClick = (e) => {
    // Prevent clicks inside the modal from closing it
    e.stopPropagation();
  };

  const handleConfirm = (e) => {
    e.preventDefault();
    e.stopPropagation();
    onConfirm();
    onClose();
  };

  const handleCancel = (e) => {
    e.preventDefault();
    e.stopPropagation();
    onClose();
  };

  return createPortal(
    <div
      style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 10002,
        backdropFilter: 'blur(4px)'
      }}
      onClick={handleOverlayClick}
    >
      <div
        style={{
          backgroundColor: 'var(--card)',
          borderRadius: 16,
          padding: 32,
          width: '100%',
          maxWidth: 420,
          boxShadow: 'var(--shadow-xl)',
          animation: 'slideIn 0.3s ease-out',
          position: 'relative',
          zIndex: 10003,
          border: '1px solid var(--border-primary)'
        }}
        onClick={handleModalClick}
      >
        {/* Header with Icon */}
        <div style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          marginBottom: 24
        }}>
          <div style={{
            width: 64,
            height: 64,
            borderRadius: '50%',
            background: 'linear-gradient(135deg, #ef4444 0%, #dc2626 100%)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            marginBottom: 16,
            boxShadow: '0 4px 12px rgba(239, 68, 68, 0.3)'
          }}>
            <span className="material-symbols-outlined" style={{
              fontSize: 32,
              color: 'white'
            }}>
              warning
            </span>
          </div>
          <h3 style={{
            margin: 0,
            marginBottom: 8,
            color: 'var(--text-primary)',
            fontSize: '1.25rem',
            fontWeight: 700,
            textAlign: 'center',
            letterSpacing: '0.01em'
          }}>
            {t('disable2FA', { ns: 'settings' })}
          </h3>
          <p style={{
            margin: 0,
            color: 'var(--text-muted)',
            fontSize: '0.95rem',
            textAlign: 'center',
            lineHeight: '1.6',
            letterSpacing: '0.01em'
          }}>
            {t('areYouSureDisable2FA', { ns: 'settings', defaultValue: 'Are you sure you want to disable two-factor authentication? This will reduce the security level of your account.' })}
          </p>
        </div>

        {/* Buttons */}
        <div style={{ display: 'flex', gap: 12, flexDirection: 'column' }}>
          <button
            type="button"
            onClick={handleConfirm}
            style={{
              width: '100%',
              padding: '16px 20px',
              borderRadius: 12,
              border: 'none',
              background: '#ef4444',
              color: '#fff',
              cursor: 'pointer',
              fontSize: '1rem',
              fontWeight: 700,
              transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: '0 4px 12px rgba(239, 68, 68, 0.25)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: '10px',
              letterSpacing: '0.03em'
            }}
            onMouseEnter={(e) => {
              e.target.style.background = '#dc2626';
              e.target.style.boxShadow = '0 6px 16px rgba(239, 68, 68, 0.35)';
              e.target.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={(e) => {
              e.target.style.background = '#ef4444';
              e.target.style.boxShadow = '0 4px 12px rgba(239, 68, 68, 0.25)';
              e.target.style.transform = 'translateY(0)';
            }}
          >
            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
              lock_open
            </span>
            {t('disable', { ns: 'settings', defaultValue: 'Disable Secure Login' })}
          </button>
          <button
            type="button"
            onClick={handleCancel}
            style={{
              width: '100%',
              padding: '14px 20px',
              borderRadius: 12,
              border: '2px solid var(--border-primary)',
              background: 'transparent',
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              fontSize: '0.95rem',
              fontWeight: 700,
              transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              letterSpacing: '0.01em'
            }}
            onMouseEnter={(e) => {
              e.target.style.borderColor = 'var(--border-secondary)';
              e.target.style.backgroundColor = 'var(--bg-hover)';
              e.target.style.color = 'var(--text-primary)';
            }}
            onMouseLeave={(e) => {
              e.target.style.borderColor = 'var(--border-primary)';
              e.target.style.backgroundColor = 'transparent';
              e.target.style.color = 'var(--text-secondary)';
            }}
          >
            {t('cancel', { ns: 'common' })}
          </button>
        </div>
      </div>

      <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateY(-20px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        @media (max-width: 1024px) {
          div[style*="maxWidth: 420"] {
            max-width: min(90vw, 400px) !important;
          }
          div[style*="padding: 32"] {
            padding: 24px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: 420"] {
            max-width: min(95vw, 380px) !important;
          }
          div[style*="padding: 32"] {
            padding: 20px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 20px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 18px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: 420"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: 32"] {
            padding: 16px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 18px !important;
          }
          p[style*="fontSize: '14px'"] {
            font-size: 12px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 16px !important;
          }
          button[style*="padding: '14px 20px'"] {
            padding: 10px 14px !important;
            font-size: 13px !important;
          }
          div[style*="width: 64"][style*="height: 64"] {
            width: 48px !important;
            height: 48px !important;
          }
          span[style*="fontSize: 32"][style*="color: 'white'"] {
            font-size: 24px !important;
          }
        }
      `}</style>
    </div>,
    document.body
  );
};

export default ConfirmDisable2FAModal;
