/**
 * Settlement Configuration Section Component
 * Handles settlement mode configuration UI
 */

import React from 'react';
import { SETTLEMENT_MODES, CYCLE_SCHEDULES } from '@/features/payment-methods/constants';
import '/styles/components/settlement-config.css';

const SettlementConfigSection = ({
  settlementConfig,
  setSettlementConfig,
  mobileMoneyAccounts,
  bankAccounts,
  onSave,
  onReset,
  isLoading = false,
}) => {
  const [isEditing, setIsEditing] = React.useState(false);

  const getModeIcon = (mode) => {
    const icons = {
      instant: 'bolt',
      t1: 'schedule',
      fixed_cycle: 'event_repeat',
      accumulated_threshold: 'account_balance_wallet',
    };
    return icons[mode] || 'settings';
  };

  const getModeColor = (mode) => {
    const colors = {
      instant: { accent: '#f59e0b', bg: 'rgba(245, 158, 11, 0.12)' },
      t1: { accent: '#3b82f6', bg: 'rgba(59, 130, 246, 0.12)' },
      fixed_cycle: { accent: '#8b5cf6', bg: 'rgba(139, 92, 246, 0.12)' },
      accumulated_threshold: { accent: '#10b981', bg: 'rgba(16, 185, 129, 0.12)' },
    };
    return colors[mode] || { accent: '#6b7280', bg: 'rgba(107, 114, 128, 0.12)' };
  };

  const formatConfigDisplay = () => {
    const mode = settlementConfig.settlementMode;
    const colors = getModeColor(mode);

    if (mode === 'instant') {
      return {
        label: 'Instant Settlement',
        value: settlementConfig.instantType === 'auto' ? 'Automatic' : 'Manual',
        icon: 'bolt',
        color: colors.accent,
      };
    }
    if (mode === 't1') {
      return {
        label: 'T+1 Settlement',
        value: 'Next Business Day',
        icon: 'schedule',
        color: colors.accent,
      };
    }
    if (mode === 'fixed_cycle') {
      const schedule = CYCLE_SCHEDULES.find(s => s.value === settlementConfig.cycleSchedule);
      return {
        label: 'Fixed Cycle Settlement',
        value: schedule?.label || settlementConfig.cycleSchedule,
        icon: 'event_repeat',
        color: colors.accent,
      };
    }
    if (mode === 'accumulated_threshold') {
      return {
        label: 'Accumulated Threshold',
        value: `${settlementConfig.thresholdCurrency} ${settlementConfig.thresholdAmount || 'Not set'}`,
        icon: 'account_balance_wallet',
        color: colors.accent,
      };
    }
    return { label: 'Not Configured', value: '', icon: 'settings', color: '#6b7280' };
  };

  const currentDisplay = formatConfigDisplay();

  const comingSoonModes = new Set(['fixed_cycle', 'accumulated_threshold']);

  return (
    <div className={`settlement-config-section ${isEditing ? 'settlement-config-section--editing' : 'settlement-config-section--view'}`} data-tour="settings-payment-settlement">
      <div className="settlement-config-header">
        <div className="settlement-config-header__icon">
          <span className="material-symbols-outlined">tune</span>
        </div>
        <div className="settlement-config-header__content">
          <div className="settlement-header-row">
            <h4 className="settlement-config-title">Settlement Configuration</h4>
            <div className="settlement-header-actions">
              {!isEditing && (
                  <button
                    type="button"
                    className="settlement-modify-btn"
                    onClick={() => setIsEditing(true)}
                  >
                    <span className="material-symbols-outlined">edit</span>
                    Modify Settings
                  </button>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="settlement-config-content">
        {/* Settlement Account Display - Moved to top */}
        <div className="settlement-config-field">
          <label className="settlement-config-field__label">
            <span className="material-symbols-outlined">account_balance</span>
            Linked Settlement Account
          </label>
          <div className="settlement-config-accounts">
            {mobileMoneyAccounts && mobileMoneyAccounts.length > 0 ? (
              <div className="settlement-config-account-item">
                <div className="settlement-config-account-item__header">
                  <span className="material-symbols-outlined">smartphone</span>
                  <span className="settlement-config-account-item__type">Mobile Money</span>
                </div>
                <div className="settlement-config-account-item__body">
                  <div className="settlement-config-account-item__name">
                    {mobileMoneyAccounts[0].accountName || 'Mobile Money Account'}
                  </div>
                  <div className="settlement-config-account-item__details">
                    {mobileMoneyAccounts[0].provider.toUpperCase() || 'MTN'} • {mobileMoneyAccounts[0].phoneNumber || mobileMoneyAccounts[0].accountNumber}
                  </div>
                </div>
              </div>
            ) : bankAccounts && bankAccounts.length > 0 ? (
              <div className="settlement-config-account-item">
                <div className="settlement-config-account-item__header">
                  <span className="material-symbols-outlined">account_balance</span>
                  <span className="settlement-config-account-item__type">Bank Account</span>
                </div>
                <div className="settlement-config-account-item__body">
                  <div className="settlement-config-account-item__name">
                    {bankAccounts[0].accountHolderName || 'Bank Account'}
                  </div>
                  <div className="settlement-config-account-item__details">
                    {bankAccounts[0].bankName} • {bankAccounts[0].accountNumber}
                  </div>
                </div>
              </div>
            ) : (
              <div className="settlement-config-account-item empty">
                <span className="material-symbols-outlined">warning</span>
                <span>No settlement account linked. Please link a MoMo or Bank account first.</span>
              </div>
            )}
          </div>
        </div>

        {/* Current Configuration Display */}
        <div className="settlement-config-current">
          <div className="settlement-config-current__header">
            <span className="material-symbols-outlined" style={{ color: currentDisplay.color }}>
              {currentDisplay.icon}
            </span>
            <span className="settlement-config-current__label">Current Mode</span>
          </div>
          <div className="settlement-config-current__body">
            <div className="settlement-config-current__mode">
              <span className="settlement-config-current__mode-label">{currentDisplay.label}</span>
              {currentDisplay.value && (
                <span className="settlement-config-current__mode-value">{currentDisplay.value}</span>
              )}
            </div>
          </div>
        </div>

        {/* Settlement Mode Selection */}
        <div className="settlement-config-field">
          <label className="settlement-config-field__label">
            <span className="material-symbols-outlined">sync_alt</span>
            Settlement Mode
          </label>
          <div className="settlement-config-modes">
            {SETTLEMENT_MODES.map((mode) => {
              const isSelected = settlementConfig.settlementMode === mode.value;
              const isComingSoon = comingSoonModes.has(mode.value);
              const colors = getModeColor(mode.value);
              return (
                <button
                  key={mode.value}
                  type="button"
                  className={`settlement-config-mode-card ${isSelected ? 'active' : ''} ${isComingSoon || !isEditing ? 'settlement-config-mode-card--disabled' : ''}`}
                  onClick={() => {
                    if (isComingSoon || !isEditing) { return; }
                    setSettlementConfig({ ...settlementConfig, settlementMode: mode.value });
                  }}
                  disabled={isComingSoon || !isEditing}
                  style={{
                    borderColor: isSelected ? colors.accent : 'var(--border-primary)',
                    backgroundColor: isSelected ? colors.bg : 'var(--bg-tertiary)',
                    opacity: (isSelected || isEditing) ? 1 : 0.7,
                    cursor: (isComingSoon || !isEditing) ? 'not-allowed' : 'pointer',
                  }}
                >
                  <span
                    className="material-symbols-outlined settlement-config-mode-card__icon"
                    style={{ color: colors.accent }}
                  >
                    {getModeIcon(mode.value)}
                  </span>
                  <div className="settlement-config-mode-card__content">
                    <span className="settlement-config-mode-card__title">{mode.label}</span>
                    <span className="settlement-config-mode-card__description">{mode.description}</span>
                  </div>
                  {isComingSoon && (
                    <span className="settlement-option-coming-soon">
                      Coming soon
                    </span>
                  )}
                  {isSelected && (
                    <span className="material-symbols-outlined settlement-config-mode-card__check">
                      check_circle
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* Instant Type (for Instant mode) */}
        {settlementConfig.settlementMode === 'instant' && (
          <div className="settlement-config-field">
            <label className="settlement-config-field__label">
              <span className="material-symbols-outlined">auto_mode</span>
              Instant Type
            </label>
            <div className={`settlement-config-options ${!isEditing ? 'disabled-container' : ''}`}>
              <button
                type="button"
                className={`settlement-config-option ${settlementConfig.instantType === 'manual' ? 'active' : ''}`}
                onClick={() => isEditing && setSettlementConfig({ ...settlementConfig, instantType: 'manual' })}
                disabled={!isEditing}
              >
                <span className="material-symbols-outlined">touch_app</span>
                <span>Manual</span>
                <span className="settlement-config-option__hint">You initiate settlements</span>
              </button>
              <button
                type="button"
                className="settlement-config-option settlement-config-option--disabled"
                onClick={() => { }}
                disabled={true}
              >
                <span className="material-symbols-outlined">auto_awesome</span>
                <span>Automatic</span>
                <span className="settlement-config-option__hint">Settles automatically</span>
                <span className="settlement-option-coming-soon">Coming soon</span>
              </button>
            </div>
          </div>
        )}

        {/* Cycle Schedule (for Fixed Cycle mode) */}
        {settlementConfig.settlementMode === 'fixed_cycle' && (
          <div className="settlement-config-field">
            <label className="settlement-config-field__label">
              <span className="material-symbols-outlined">calendar_today</span>
              Schedule Frequency
            </label>
            <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '8px' }}>
              Coming soon
            </div>
            <div className="settlement-config-options">
              {CYCLE_SCHEDULES.map((schedule) => (
                <button
                  key={schedule.value}
                  type="button"
                  className={`settlement-config-option ${settlementConfig.cycleSchedule === schedule.value ? 'active' : ''}`}
                  onClick={() => { }}
                  disabled
                  style={{ opacity: 0.6, cursor: 'not-allowed' }}
                >
                  <span className="material-symbols-outlined">
                    {schedule.value === 'daily' ? 'today' : schedule.value === 'weekly' ? 'date_range' : 'calendar_month'}
                  </span>
                  <span>{schedule.label}</span>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Threshold Amount (for Accumulated Threshold mode) */}
        {settlementConfig.settlementMode === 'accumulated_threshold' && (
          <div className="settlement-config-field">
            <label className="settlement-config-field__label">
              <span className="material-symbols-outlined">payments</span>
              Threshold Amount
            </label>
            <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginBottom: '8px' }}>
              Coming soon
            </div>
            <div className="settlement-config-threshold">
              <div className="settlement-config-threshold__input-group">
                <select
                  value={settlementConfig.thresholdCurrency}
                  onChange={() => { }}
                  className="settlement-config-threshold__currency"
                  disabled
                >
                  <option value="GHS">GHS</option>
                </select>
                <input
                  type="number"
                  placeholder="Enter threshold amount"
                  value={settlementConfig.thresholdAmount}
                  onChange={() => { }}
                  className="settlement-config-threshold__amount"
                  min="0"
                  step="0.01"
                  disabled
                />
              </div>
              <p className="settlement-config-field__hint">
                Settlement will trigger when accumulated balance reaches this amount
              </p>
            </div>
          </div>
        )}



        {/* Action Buttons - Only visible when editing */}
        {isEditing && (
          <div className="settlement-config-actions">
            <button
              type="button"
              onClick={() => {
                onReset();
                setIsEditing(false);
              }}
              disabled={isLoading}
              className="settlement-config-action-btn settlement-config-action-btn--secondary"
            >
              <span className="material-symbols-outlined">close</span>
              Discard
            </button>
            <button
              type="button"
              onClick={async () => {
                try {
                  await onSave(settlementConfig);
                  setIsEditing(false);
                } catch (e) { }
              }}
              disabled={isLoading}
              className="settlement-config-action-btn settlement-config-action-btn--primary"
            >
              {isLoading ? (
                <>
                  <span className="material-symbols-outlined spinning">sync</span>
                  Applying...
                </>
              ) : (
                <>
                  <span className="material-symbols-outlined">save</span>
                  Apply Configuration
                </>
              )}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default SettlementConfigSection;

