/**
 * Mobile Money Account Form Component
 * Shared form for adding/editing mobile money accounts
 */

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { FlagIcon } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { MOBILE_MONEY_PROVIDERS } from '@/features/payment-methods/constants';
import { disbursementService } from '@/features/disbursements/services';
import { mapProviderToIVerifyOperator } from '@/features/disbursements/utils/helpers.js';

const MobileMoneyAccountForm = ({
  formData,
  onChange,
  onSubmit,
  onCancel,
  isEditing,
  isLoading = false,
}) => {
  const { t } = useTranslation();
  const { success, error } = useToast();
  const [isValidatingAccount, setIsValidatingAccount] = useState(false);
  const [accountDetailsFetched, setAccountDetailsFetched] = useState(false);

  const handleProviderChange = (value) => {
    onChange({
      ...formData,
      provider: value,
      accountName: '',
    });
    setAccountDetailsFetched(false);
  };

  const handlePhoneChange = (value) => {
    let nextValue = value;
    if (nextValue && nextValue.startsWith('0')) {
      nextValue = nextValue.substring(1);
    }
    onChange({
      ...formData,
      phoneNumber: nextValue,
      accountName: '',
    });
    setAccountDetailsFetched(false);
  };

  const canFetchAccountDetails = () => {
    if (!formData.phoneNumber || !formData.phoneNumber.trim()) {
      return false;
    }
    if (!formData.provider || !formData.provider.trim()) {
      return false;
    }
    return true;
  };

  const handleFetchAccountDetails = async () => {
    if (!formData.phoneNumber || !formData.phoneNumber.trim()) {
      error('Please enter a phone number');
      return;
    }
    if (!formData.provider || !formData.provider.trim()) {
      error('Please select a Mobile Money Provider');
      return;
    }

    setIsValidatingAccount(true);
    try {
      let mobileNumber = formData.phoneNumber.trim();
      if (mobileNumber.startsWith('+233')) {
        mobileNumber = mobileNumber.substring(4);
      } else if (mobileNumber.startsWith('233')) {
        mobileNumber = mobileNumber.substring(3);
      }
      if (mobileNumber.startsWith('0')) {
        mobileNumber = mobileNumber.substring(1);
      }
      mobileNumber = `0${mobileNumber}`;

      const operator = mapProviderToIVerifyOperator(formData.provider);
      const response = await disbursementService.verifyMobileMoneyIdentity({
        mobileNumber,
        operator,
      });

      if (response?.status === 'success' && response?.name) {
        // Update state first
        setAccountDetailsFetched(true);
        onChange({
          ...formData,
          accountName: response.name,
        });
        
        // Then show success message
        success('Account details fetched successfully');
        return;
      }

      error('Unable to fetch account details');
    } catch (fetchError) {
      error(fetchError?.message || 'Unable to fetch account details');
    } finally {
      setIsValidatingAccount(false);
    }
  };
  return (
    <div
      style={{
        padding: '20px',
        border: '1px solid var(--border-primary)',
        borderRadius: '8px',
        backgroundColor: 'var(--bg-tertiary)',
      }}
    >
      <h4 style={{ marginTop: 0, marginBottom: 20, color: 'var(--text-primary)' }}>
        {isEditing ? 'Edit Mobile Money Account' : 'Add Mobile Money Account'}
      </h4>
      <div style={{ display: 'grid', gap: '16px', maxWidth: '100%' }}>
        {/* Row 1: Provider and Currency */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
          <div>
            <label
              style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
              }}
            >
              {t('mobileMoneyProvider', { ns: 'settings', defaultValue: 'Mobile Money Provider' })}
            </label>
            <select
              value={formData.provider}
              onChange={(e) => handleProviderChange(e.target.value)}
              style={{
                width: '100%',
                padding: '12px',
                border: '1px solid var(--border-secondary)',
                borderRadius: 'var(--radius-md)',
                fontSize: '14px',
                transition: 'all var(--transition-base)',
                backgroundColor: 'var(--bg-input)',
                color: 'var(--text-primary)',
              }}
            >
              <option value="" disabled>{t('selectNetwork', { ns: 'settings', defaultValue: 'Select Network' })}</option>
              {MOBILE_MONEY_PROVIDERS.map(provider => (
                <option key={provider.value} value={provider.value}>
                  {provider.label}
                </option>
              ))}
            </select>
          </div>
          <div>
            <label
              style={{
                display: 'block',
                marginBottom: '8px',
                color: 'var(--text-primary)',
              }}
            >
              {t('currency', { ns: 'settings', defaultValue: 'Currency' })}
            </label>
            <select
              value={formData.currency}
              onChange={(e) => onChange({ ...formData, currency: e.target.value })}
              style={{
                width: '100%',
                padding: '10px',
                border: '1px solid var(--border-secondary)',
                borderRadius: '6px',
                fontSize: '14px',
                backgroundColor: 'var(--bg-input)',
                color: 'var(--text-primary)',
              }}
            >
              <option value="GHS">GHS</option>
            </select>
          </div>
        </div>

        {/* Row 2: Phone Number */}
        <div>
          <label
            style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
            }}
          >
            Phone Number
          </label>
          <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'nowrap' }}>
            <div style={{ position: 'relative', width: '120px', flexShrink: 0, minWidth: '120px' }}>
              <span
                style={{
                  position: 'absolute',
                  left: '12px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  pointerEvents: 'none',
                  zIndex: 1,
                  display: 'flex',
                  alignItems: 'center',
                }}
              >
                <FlagIcon
                  countryCode={countries.find((c) => c.dialCode === (formData.countryCode || '+233'))?.code || 'GH'}
                  size="1.1em"
                />
              </span>
              <CustomSelect
                name="countryCode"
                value={formData.countryCode || '+233'}
                onChange={(e) => onChange({ ...formData, countryCode: e.target.value })}
                options={countries.map((country) => ({
                  value: country.dialCode,
                  label: country.dialCode,
                  name: country.name,
                  countryCode: country.code,
                }))}
                searchable
                showCheckmark={false}
                style={{ width: '100%' }}
              />
            </div>
            <input
              type="tel"
              placeholder="Enter your mobile money number"
              value={formData.phoneNumber}
              onChange={(e) => handlePhoneChange(e.target.value)}
              style={{
                flex: 1,
                padding: '10px 12px',
                border: '1px solid var(--border-secondary)',
                borderRadius: '6px',
                fontSize: '14px',
                backgroundColor: 'var(--bg-input)',
                color: 'var(--text-primary)',
              }}
            />
          </div>
        </div>

        {/* Row 3: Mobile Number Name */}
        <div>
          <label
            style={{
              display: 'block',
              marginBottom: '8px',
              color: 'var(--text-primary)',
            }}
          >
            Mobile Number Name
          </label>
          <input
            type="text"
            placeholder="Mobile number name"
            value={formData.accountName || ''}
            readOnly
            disabled
            style={{
              width: '100%',
              padding: '10px',
              border: '1px solid var(--border-secondary)',
              borderRadius: '6px',
              fontSize: '14px',
              backgroundColor: 'var(--bg-tertiary)',
              color: 'var(--text-primary)',
            }}
          />
        </div>

        <div style={{ display: 'flex', gap: '12px', alignItems: 'center' }}>
          <button
            type="button"
            onClick={handleFetchAccountDetails}
            disabled={isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()}
            style={{
              padding: '10px 16px',
              borderRadius: '6px',
              border: '1px solid var(--border-secondary)',
              backgroundColor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'var(--bg-input)'
                : '#004895',
              color: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'var(--text-muted)'
                : 'white',
              cursor: isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails()
                ? 'not-allowed'
                : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
            }}
          >
            {isValidatingAccount ? 'Fetching...' : accountDetailsFetched ? 'Details Fetched' : 'Fetch Account Details'}
          </button>
          {!canFetchAccountDetails() && !isValidatingAccount && !accountDetailsFetched && (
            <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
              Enter provider and phone number to fetch
            </span>
          )}
        </div>

        {/* Action Buttons */}
        <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
          <button
            onClick={onSubmit}
            disabled={isLoading}
            style={{
              padding: '10px 20px',
              backgroundColor: '#004895',
              color: 'white',
              border: 'none',
              borderRadius: '6px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
              opacity: isLoading ? 0.6 : 1,
            }}
          >
            {isLoading ? 'Saving...' : (isEditing ? 'Update Account' : 'Add Account')}
          </button>
          <button
            onClick={onCancel}
            disabled={isLoading}
            style={{
              padding: '10px 20px',
              backgroundColor: 'transparent',
              color: '#6b7280',
              border: '1px solid #d1d5db',
              borderRadius: '6px',
              cursor: isLoading ? 'not-allowed' : 'pointer',
              fontSize: '14px',
              fontWeight: '500',
            }}
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default MobileMoneyAccountForm;





