/**
 * Account mapping utilities for PaymentMethods
 * Maps API responses to frontend format
 */

/**
 * Map API account response to bank account format
 * @param {object} account - Account object from API
 * @returns {object} Formatted bank account
 */
export const mapBankAccount = (account) => {
  return {
    id: account.id,
    accountHolderName: account.payment_details?.account_holder_name || account.account_holder_name || account.accountHolderName || '',
    bankName: account.payment_details?.bank_name || account.bank_name || account.bankName || '',
    accountNumber: (account.payment_details?.account_number || account.account_number) 
      ? `****${String(account.payment_details?.account_number || account.account_number).slice(-4)}` 
      : '',
    rawAccountNumber: account.payment_details?.account_number || account.account_number || '',
    accountType: account.payment_details?.account_category || account.account_category || account.accountType || '',
    branch: account.payment_details?.branch || account.branch || '',
    swiftCode: account.payment_details?.swift_bic || account.swift_bic || account.swiftCode || '',
    isDefault: !!account.is_default,
    isVerified: !!account.is_verified,
  };
};

/**
 * Map API account response to mobile money account format
 * @param {object} account - Account object from API
 * @returns {object} Formatted mobile money account
 */
export const mapMobileMoneyAccount = (account) => {
  return {
    id: account.id,
    provider: account.payment_details?.provider
      || account.payment_details?.network
      || account.network
      || account.provider
      || '',
    phoneNumber: account.payment_details?.account_number || account.account_number || account.phone || '',
    accountName: account.payment_details?.account_name 
      || account.payment_details?.accountName 
      || account.payment_details?.name 
      || account.payment_details?.account_holder_name
      || account.account_name 
      || account.accountName 
      || account.name 
      || account.holder_name
      || account.account_holder_name
      || '',
    currency: account.payment_details?.currency || account.currency || 'GHS',
    isDefault: !!account.is_default,
    isVerified: !!account.is_verified,
  };
};

/**
 * Filter and map accounts by type
 * @param {Array} accounts - Array of account objects from API
 * @returns {{banks: Array, momos: Array}} Filtered and mapped accounts
 */
export const filterAndMapAccounts = (accounts) => {
  const banks = accounts
    .filter(a => {
      const type = (a.channel || a.account_type || a.accountType || '').toUpperCase();
      return type === 'BANK';
    })
    .map(mapBankAccount);

  const momos = accounts
    .filter(a => {
      const type = (a.channel || a.account_type || a.accountType || '').toUpperCase();
      return type === 'MOMO';
    })
    .map(mapMobileMoneyAccount);

  return { banks, momos };
};





