import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { X, CheckCircle, AlertTriangle, LogOut } from 'lucide-react';
import { authService } from '@/features/auth/services/coreAuthService.js';

const TwoFactorSetupModal = ({
  isOpen,
  onClose,
  qrCode,
  secret,
  onConfirmScanned,
  isConfirming
}) => {
  const { t } = useTranslation();
  const [hasScanned, setHasScanned] = useState(false);

  if (!isOpen) { return null; }

  const handleConfirmScanned = () => {
    // Show success message and logout after 3 seconds
    setHasScanned(true);
    setTimeout(() => {
      handleLogout();
    }, 3000);
  };



  const handleLogout = async () => {
    try {
      // Call the logout API to invalidate server-side session
      await authService.logout();

      // Clear local storage and redirect
      localStorage.removeItem('authToken');
      localStorage.removeItem('accessToken');
      localStorage.removeItem('refreshToken');
      localStorage.removeItem('userData');
      window.location.href = '/login';
    } catch (error) {
      // Even if API call fails, still clear local storage and redirect
      logger.error('Logout API call failed:', error);
      localStorage.removeItem('authToken');
      localStorage.removeItem('accessToken');
      localStorage.removeItem('refreshToken');
      localStorage.removeItem('userData');
      window.location.href = '/login';
    }
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  const handleModalClick = (e) => {
    e.stopPropagation();
  };

  return createPortal(
    <div
      style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.6)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 999999,
        padding: '20px'
      }}
      onClick={handleOverlayClick}
    >
      <div
        style={{
          backgroundColor: 'var(--card)',
          borderRadius: '16px',
          maxWidth: '500px',
          width: '100%',
          maxHeight: '90vh',
          overflow: 'auto',
          position: 'relative',
          boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
          transform: 'scale(1)',
          animation: 'modalSlideIn 0.3s ease-out'
        }}
        onClick={handleModalClick}
      >
        {/* Close button in top-right corner */}
        <button
          onClick={onClose}
          disabled={isConfirming}
          style={{
            position: 'absolute',
            top: '16px',
            right: '16px',
            background: 'none',
            border: 'none',
            cursor: isConfirming ? 'not-allowed' : 'pointer',
            padding: '8px',
            borderRadius: '8px',
            color: 'var(--text-muted)',
            transition: 'all 0.2s',
            zIndex: 1
          }}
        >
          <X size={20} />
        </button>

        {/* Content */}
        <div style={{ padding: '24px' }}>
          {/* Warning Message */}
          <div style={{
            backgroundColor: 'var(--warning-bg, #fef3c7)',
            border: '1px solid var(--warning-border, #f59e0b)',
            borderRadius: '8px',
            padding: '12px 16px',
            marginBottom: '24px',
            display: 'flex',
            alignItems: 'flex-start',
            gap: '12px'
          }}>
            <AlertTriangle size={20} style={{ color: 'var(--warning-text, #d97706)', flexShrink: 0 }} />
            <div>
              <p style={{
                margin: 0,
                fontSize: '14px',
                fontWeight: '500',
                color: 'var(--warning-text, #d97706)'
              }}>
                Don't Skip This Step!
              </p>
              <p style={{
                margin: '4px 0 0',
                fontSize: '13px',
                color: 'var(--warning-text, #d97706)'
              }}>
                You must scan this QR code with your authenticator app (like Google Authenticator) and verify it works. Otherwise, you could be locked out of your account.
              </p>
            </div>
          </div>

          {/* QR Code Section */}
          <div style={{ textAlign: 'center', marginBottom: '24px' }}>

            <div style={{
              width: '220px',
              height: '220px',
              margin: '0 auto 16px',
              backgroundColor: 'var(--bg-secondary)',
              border: '2px solid var(--border-primary)',
              borderRadius: '12px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              padding: '16px',
              position: 'relative'
            }}>
              {qrCode ? (
                <img
                  src={qrCode}
                  alt="2FA QR Code"
                  style={{
                    width: '100%',
                    height: '100%',
                    objectFit: 'contain',
                    borderRadius: '8px'
                  }}
                />
              ) : (
                <div style={{ textAlign: 'center' }}>
                  <div style={{
                    width: '40px',
                    height: '40px',
                    border: '3px solid var(--border-primary)',
                    borderTop: '3px solid var(--accent)',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite',
                    margin: '0 auto 12px'
                  }} />
                  <p style={{
                    margin: 0,
                    fontSize: '14px',
                    color: 'var(--text-muted)'
                  }}>
                    Generating QR code...
                  </p>
                </div>
              )}
            </div>

            {/* Manual Entry */}
            <div style={{
              backgroundColor: 'var(--bg-secondary)',
              borderRadius: '8px',
              padding: '12px',
              marginBottom: '16px'
            }}>
              <p style={{
                margin: '0 0 8px',
                fontSize: '13px',
                color: 'var(--text-muted)'
              }}>
                Can't scan the QR code?
              </p>
              <code style={{
                backgroundColor: 'var(--bg-primary)',
                padding: '8px 12px',
                borderRadius: '6px',
                fontSize: '14px',
                color: 'var(--text-primary)',
                border: '1px solid var(--border-primary)',
                display: 'inline-block',
                fontFamily: 'monospace',
                wordBreak: 'break-all'
              }}>
                {secret}
              </code>
              <p style={{
                margin: '8px 0 0',
                fontSize: '12px',
                color: 'var(--text-muted)'
              }}>
                Enter this code manually in your authenticator app
              </p>
            </div>
          </div>

          {/* Success Message with Countdown */}
          {hasScanned && (
            <div style={{
              backgroundColor: 'var(--accent, #2563eb)',
              border: '1px solid var(--accent-dark, #1d4ed8)',
              borderRadius: '8px',
              padding: '16px',
              textAlign: 'center',
              marginBottom: '24px'
            }}>
              <CheckCircle size={32} style={{ color: 'white', marginBottom: '8px' }} />
              <p style={{
                margin: '0 0 8px',
                fontSize: '16px',
                fontWeight: '600',
                color: 'white'
              }}>
                2FA Setup Complete!
              </p>
              <p style={{
                margin: '0',
                fontSize: '14px',
                color: 'white'
              }}>
                You will be automatically logged out in 3 seconds for security.
              </p>
              <p style={{
                margin: '8px 0 0',
                fontSize: '13px',
                color: 'rgba(255, 255, 255, 0.8)'
              }}>
                Please log back in with your 2FA code.
              </p>
            </div>
          )}

          {/* Instructions */}
          <div style={{
            backgroundColor: 'var(--bg-secondary)',
            borderRadius: '8px',
            padding: '16px',
            marginBottom: '24px'
          }}>
            <div>
              <ol style={{
                margin: 0,
                paddingLeft: '20px',
                fontSize: '13px',
                color: 'var(--text-muted)',
                lineHeight: '1.6'
              }}>
                <li style={{ marginBottom: '8px' }}>
                  Download an authenticator app (Google Authenticator, Microsoft Authenticator, or Authy)
                </li>
                <li style={{ marginBottom: '8px' }}>
                  Open the app and tap "+" to add a new account
                </li>
                <li style={{ marginBottom: '8px' }}>
                  Scan the QR code above or enter the manual code
                </li>
                <li style={{ marginBottom: '8px' }}>
                  Verify it's working by opening the app and seeing the 6-digit code for iSmartPay
                </li>
              </ol>
            </div>
          </div>

          {/* Action Buttons */}
          <div style={{ display: 'flex', gap: '12px', flexDirection: 'column' }}>
            {!hasScanned && (
              <button
                onClick={handleConfirmScanned}
                disabled={!qrCode || isConfirming}
                style={{
                  padding: '14px 20px',
                  backgroundColor: qrCode && !isConfirming ? 'var(--accent)' : 'var(--bg-tertiary)',
                  color: qrCode && !isConfirming ? 'var(--text-inverse)' : 'var(--text-muted)',
                  border: 'none',
                  borderRadius: '8px',
                  fontSize: '15px',
                  fontWeight: '500',
                  cursor: qrCode && !isConfirming ? 'pointer' : 'not-allowed',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '8px',
                  transition: 'all 0.2s'
                }}
              >
                <CheckCircle size={18} />
                I've Scanned the QR Code
              </button>
            )}
          </div>
        </div>
      </div>
    </div>,
    document.body
  );
};

export default TwoFactorSetupModal;
