import { z } from 'zod';
import { trimAndRequire, phoneNumberSchema, numericString } from './helpers';

const passwordField = (t) =>
  z
    .string()
    .min(8, t('newPasswordMustBe8Chars', { ns: 'settings', defaultValue: 'Password must be at least 8 characters' }))
    .superRefine((val, ctx) => {
      if (!/[A-Z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainUppercase', { ns: 'auth' }),
        });
      }
      if (!/[a-z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainLowercase', { ns: 'auth' }),
        });
      }
      if (!/[0-9]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainNumber', { ns: 'auth' }),
        });
      }
      // Allow all special characters (any character that is not alphanumeric or whitespace)
      if (!/[^a-zA-Z0-9\s]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainSpecial', { ns: 'auth' }),
        });
      }
    });

export const createIndividualSettingsSchema = (t) =>
  z
    .object({
      country: trimAndRequire(
        t('countryRequired', { ns: 'settings', defaultValue: 'Country is required' })
      ),
      city: trimAndRequire(
        t('cityRequired', { ns: 'settings', defaultValue: 'City is required' })
      ),
      area: trimAndRequire(
        t('areaRequired', { ns: 'settings', defaultValue: 'Area is required' })
      ),
      digital_address: trimAndRequire(
        t('digitalAddressRequired', {
          ns: 'settings',
          defaultValue: 'Digital address is required',
        })
      ).max(
        100,
        t('digitalAddressTooLong', {
          ns: 'settings',
          defaultValue: 'Digital address cannot exceed 100 characters',
        })
      ),
      currency: trimAndRequire(
        t('currencyRequired', { ns: 'settings', defaultValue: 'Currency is required' })
      ),
      language: trimAndRequire(
        t('languageRequired', { ns: 'settings', defaultValue: 'Language is required' })
      ),
      notificationPreference: trimAndRequire(
        t('notificationPreferenceRequired', {
          ns: 'settings',
          defaultValue: 'Notification preference is required',
        })
      ),
      theme: trimAndRequire(
        t('themeRequired', { ns: 'settings', defaultValue: 'Theme is required' })
      ),
      timezone: trimAndRequire(
        t('timezoneRequired', { ns: 'settings', defaultValue: 'Timezone is required' })
      ),
    })
    .transform((data) => ({
      country: data.country.trim(),
      city: data.city.trim(),
      area: data.area.trim(),
      digital_address: data.digital_address.trim(),
      currency: data.currency.trim(),
      language: data.language.trim(),
      notificationPreference: data.notificationPreference.trim(),
      theme: data.theme.trim(),
      timezone: data.timezone.trim(),
    }));

export const createBusinessSettingsSchema = (t) =>
  z
    .object({
      fullName: trimAndRequire(
        t('fullNameRequired', { ns: 'settings', defaultValue: 'Full name is required' })
      ),
      phoneNumber: phoneNumberSchema(
        t('invalidPhoneFormat', { ns: 'settings', defaultValue: 'Please enter a valid phone number (numeric only)' }),
        t('phoneNumberLength', { ns: 'settings', defaultValue: 'Phone number must be between 7 and 15 digits' })
      ),
      country: trimAndRequire(
        t('countryRequired', { ns: 'settings', defaultValue: 'Country is required' })
      ),
      area: trimAndRequire(
        t('areaRequired', { ns: 'settings', defaultValue: 'Area is required' })
      ),
      residential_address: z
        .string()
        .optional()
        .transform((val) => val?.trim() || '')
        .refine(
          (val) => !val || val.length <= 150,
          t('residentialAddressTooLong', {
            ns: 'settings',
            defaultValue: 'Residential address cannot exceed 150 characters',
          })
        ),
      digital_address: z
        .string()
        .optional()
        .transform((val) => val?.trim() || '')
        .refine(
          (val) => !val || val.length <= 100,
          t('digitalAddressTooLong', {
            ns: 'settings',
            defaultValue: 'Digital address cannot exceed 100 characters',
          })
        ),
      dob: z.string().optional(),
      currency: trimAndRequire(
        t('currencyRequired', { ns: 'settings', defaultValue: 'Currency is required' })
      ),
      language: trimAndRequire(
        t('languageRequired', { ns: 'settings', defaultValue: 'Language is required' })
      ),
      notificationPreference: trimAndRequire(
        t('notificationPreferenceRequired', {
          ns: 'settings',
          defaultValue: 'Notification preference is required',
        })
      ),
      theme: trimAndRequire(
        t('themeRequired', { ns: 'settings', defaultValue: 'Theme is required' })
      ),
      timezone: trimAndRequire(
        t('timezoneRequired', { ns: 'settings', defaultValue: 'Timezone is required' })
      ),
    })
    .transform((data) => ({
      country: data.country.trim(),
      area: data.area.trim(),
      residential_address: data.residential_address || '',
      digital_address: data.digital_address || '',
      dob: data.dob || '',
      currency: data.currency.trim(),
      language: data.language.trim(),
      notificationPreference: data.notificationPreference.trim(),
      theme: data.theme.trim(),
      timezone: data.timezone.trim(),
    }));

export const createPasswordChangeSchema = (t) =>
  z
    .object({
      currentPassword: trimAndRequire(
        t('currentPasswordRequired', {
          ns: 'settings',
          defaultValue: 'Current password is required',
        })
      ),
      newPassword: passwordField(t),
      confirmNewPassword: trimAndRequire(
        t('confirmNewPasswordRequired', {
          ns: 'settings',
          defaultValue: 'Confirm password is required',
        })
      ),
    })
    .superRefine((data, ctx) => {
      if (data.newPassword !== data.confirmNewPassword) {
        ctx.addIssue({
          path: ['confirmNewPassword'],
          code: z.ZodIssueCode.custom,
          message: t('newPasswordsDoNotMatch', { ns: 'settings' }),
        });
      }
    });

export const createPinSchema = (t) =>
  z
    .object({
      pin: numericString(t('pinMustBe4Digits', { ns: 'settings' })).refine(
        (val) => val.length === 4,
        {
          message: t('pinMustBe4Digits', { ns: 'settings' }),
        }
      ),
      confirm: numericString(t('pinMustBe4Digits', { ns: 'settings' })).refine(
        (val) => val.length === 4,
        {
          message: t('pinMustBe4Digits', { ns: 'settings' }),
        }
      ),
    })
    .superRefine((data, ctx) => {
      if (data.pin !== data.confirm) {
        ctx.addIssue({
          path: ['confirm'],
          code: z.ZodIssueCode.custom,
          message: t('pinsDoNotMatch', { ns: 'settings' }),
        });
      }
    });

export const createTeamSchema = (t) =>
  z.object({
    name: trimAndRequire(
      t('teamNameRequired', { ns: 'settings', defaultValue: 'Team name is required' })
    ).max(
      80,
      t('teamNameTooLong', {
        ns: 'settings',
        defaultValue: 'Team name cannot exceed 80 characters',
      })
    ),
    pageAccess: z
      .array(z.string().trim())
      .min(1, t('selectAtLeastOnePage', { ns: 'settings' })),
  });

export const createTeamMemberSchema = (t) =>
  z.object({
    name: trimAndRequire(
      t('memberNameRequired', { ns: 'settings', defaultValue: 'Member name is required' })
    ).max(
      100,
      t('memberNameTooLong', {
        ns: 'settings',
        defaultValue: 'Member name cannot exceed 100 characters',
      })
    ),
    email: z
      .string()
      .trim()
      .min(1, t('emailRequired', { ns: 'auth' }))
      .email(t('pleaseEnterValidEmailAddress', { ns: 'auth' })),
    phoneCountryCode: trimAndRequire(
      t('phoneCountryCodeRequired', { ns: 'auth', defaultValue: 'Select a country code' })
    ),
    phoneNumber: phoneNumberSchema(
      t('invalidPhone', { ns: 'auth' }),
      t('phoneNumberLength', { ns: 'auth' })
    ),
    role: trimAndRequire(
      t('roleRequired', { ns: 'settings', defaultValue: 'Role is required' })
    ),
  });



