/**
 * Payment Methods Tabs Component
 * Handles tab navigation for payment methods page
 */

import React from 'react';

const PaymentMethodsTabs = ({ activeTab, onTabChange, onTabSwitch }) => {
  const tabs = [
    { key: 'settlement-account', label: 'Settlement Account', icon: 'account_balance_wallet' },
    { key: 'settlement-config', label: 'Settlement Configuration', icon: 'settings' },
  ];

  const handleTabClick = (tabKey) => {
    onTabChange(tabKey);
    if (onTabSwitch) {
      onTabSwitch();
    }
  };

  return (
    <div
      data-tour="settings-payment-tabs"
      style={{
        display: 'flex',
        gap: '8px',
        marginBottom: '24px',
        borderBottom: '1px solid var(--border-primary)',
      }}
    >
      {tabs.map((tab) => (
        <button
          key={tab.key}
          onClick={() => handleTabClick(tab.key)}
          style={{
            padding: '12px 16px',
            background: activeTab === tab.key ? 'var(--accent)' : 'transparent',
            color: activeTab === tab.key ? 'var(--text-inverse)' : 'var(--text-muted)',
            border: 'none',
            borderRadius: '8px 8px 0 0',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: activeTab === tab.key ? '600' : '400',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            transition: 'all var(--transition-base)',
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: 18 }}>
            {tab.icon}
          </span>
          {tab.label}
        </button>
      ))}
    </div>
  );
};

export default PaymentMethodsTabs;

