/**
 * Profile Utilities
 * 
 * Provides utility functions for managing user profile data including loading
 * from API and localStorage, updating preferences, mapping profile data to form
 * structures, and handling user preference synchronization between frontend and
 * backend systems.
 */

import { profileService } from '../services/index.js';
import logger from '@/shared/utils/logger.js';

export class ProfileUtils {
  static async loadUserProfile() {
    const userDataObj = JSON.parse(localStorage.getItem('userData') || '{}');

    try {
      const profileResponse = await profileService.getUserProfile();
      const apiData = profileResponse?.data;

      let apiPreferences = null;
      try {
        const preferencesResponse = await profileService.getUserPreferences();
        const preferencesData = preferencesResponse?.data;
        if (preferencesData) {
          apiPreferences = {
            currency: preferencesData.currency || 'GHS',
            language: preferencesData.language || 'en',
            notificationPreference: preferencesData.notification_preference || 'email',
            theme: userDataObj.preferences?.theme || 'Light',
            timezone: userDataObj.preferences?.timezone || 'Africa/Accra'
          };
        }
      } catch (preferencesError) {
        logger.debug('Preferences API call failed, using defaults', { error: preferencesError.message });
      }

      if (apiData && Object.keys(apiData).length > 0) {
        const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Preserve the original login user ID - don't let profile data overwrite it
        const preservedId = currentUserData.id;
        const { id: apiDataId, ...apiDataWithoutId } = apiData;

        // Merge preferences, preserving existing theme and timezone if API doesn't return them
        const mergedPreferences = {
          ...currentUserData.preferences, // Preserve existing preferences first
          ...(apiPreferences || {}), // Then apply API preferences
          // Always preserve theme and timezone from localStorage if API doesn't provide them
          theme: apiPreferences?.theme || currentUserData.preferences?.theme || 'Light',
          timezone: apiPreferences?.timezone || currentUserData.preferences?.timezone || 'Africa/Accra',
        };

        const freshUserData = {
          ...currentUserData,
          ...apiDataWithoutId,
          id: preservedId, // Always preserve the login user ID
          // Preserve residential_address if API doesn't return it
          residential_address: apiDataWithoutId.residential_address || currentUserData.residential_address,
          preferences: mergedPreferences,
          updated_at: new Date().toISOString()
        };
        localStorage.setItem('userData', JSON.stringify(freshUserData));
        return freshUserData;
      }
    } catch (apiError) {
      logger.debug('Profile API call failed, using stored data', { error: apiError.message });
    }

    if (userDataObj && Object.keys(userDataObj).length > 0) {
      return userDataObj;
    }

    return userDataObj;
  }

  static async loadContactPersonProfile() {
    const userDataObj = JSON.parse(localStorage.getItem('userData') || '{}');

    try {
      const { contactPersonService } = await import('../services/index.js');
      const profileResponse = await contactPersonService.getPersonalInfo();
      const apiData = profileResponse?.data;

      let apiPreferences = null;
      try {
        const preferencesResponse = await profileService.getUserPreferences();
        const preferencesData = preferencesResponse?.data;
        if (preferencesData) {
          apiPreferences = {
            currency: preferencesData.currency || 'GHS',
            language: preferencesData.language || 'en',
            notificationPreference: preferencesData.notification_preference || 'email',
            theme: userDataObj.preferences?.theme || 'Light',
            timezone: userDataObj.preferences?.timezone || 'Africa/Accra'
          };
        }
      } catch (preferencesError) {
        logger.debug('Preferences API call failed, using defaults', { error: preferencesError.message });
      }

      if (apiData && Object.keys(apiData).length > 0) {
        const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
        // Preserve the original login user ID - don't let profile data overwrite it
        const preservedId = currentUserData.id;
        const { id: apiDataId, ...apiDataWithoutId } = apiData;

        // Merge preferences, preserving existing theme and timezone if API doesn't return them
        const mergedPreferences = {
          ...currentUserData.preferences, // Preserve existing preferences first
          ...(apiPreferences || {}), // Then apply API preferences
          // Always preserve theme and timezone from localStorage if API doesn't provide them
          theme: apiPreferences?.theme || currentUserData.preferences?.theme || 'Light',
          timezone: apiPreferences?.timezone || currentUserData.preferences?.timezone || 'Africa/Accra',
        };

        const freshUserData = {
          ...currentUserData,
          ...apiDataWithoutId,
          id: preservedId, // Always preserve the login user ID
          // Preserve residential_address if API doesn't return it
          residential_address: apiDataWithoutId.residential_address || currentUserData.residential_address,
          preferences: mergedPreferences,
          updated_at: new Date().toISOString()
        };
        localStorage.setItem('userData', JSON.stringify(freshUserData));
        return freshUserData;
      }
    } catch (apiError) {
      logger.debug('Contact person profile API call failed, using stored data', { error: apiError.message });
    }

    if (userDataObj && Object.keys(userDataObj).length > 0) {
      return userDataObj;
    }

    return userDataObj;
  }

  static mapContactPersonDataToForm(profileData, preferences) {
    if (!profileData || Object.keys(profileData).length === 0) {
      return null;
    }

    const prefs = preferences || {};

    return {
      fullName: profileData.full_name || profileData.fullName || '',
      phoneNumber: profileData.phone_number || profileData.phone || '',
      country: profileData.country || 'Ghana',
      city: profileData.city || '',
      area: profileData.area || '',
      digital_address: profileData.digital_address || profileData.digitalAddress || '',
      residential_address: profileData.residential_address || profileData.residentialAddress || '',
      dob: profileData.dob || '',
      currency: prefs.currency || 'GHS',
      language: prefs.language || 'en',
      notificationPreference: prefs.notification_preference || prefs.notificationPreference || 'email',
      theme: prefs.theme || 'Light',
      timezone: prefs.timezone || 'Africa/Accra'
    };
  }

  static mapProfileDataToForm(profileDataRaw, preferences) {
    // Handle potential nesting under 'data'
    const profileData = profileDataRaw?.data || profileDataRaw;

    if (!profileData || Object.keys(profileData).length === 0) {
      return null;
    }

    let firstName = profileData.first_name || profileData.firstName || '';
    let lastName = profileData.last_name || profileData.lastName || '';

    if (profileData.full_name && (!firstName || !lastName)) {
      const nameParts = profileData.full_name.trim().split(' ');
      if (nameParts.length >= 2) {
        firstName = nameParts[0];
        lastName = nameParts.slice(1).join(' ');
      } else {
        firstName = profileData.full_name;
        lastName = '';
      }
    }

    const prefs = preferences || {};

    return {
      firstName: firstName,
      lastName: lastName,
      fullName: profileData.full_name || `${firstName} ${lastName}`.trim() || profileData.fullName || '',
      phoneNumber: profileData.phone_number || profileData.phone || '',
      country: profileData.country || 'Ghana',
      city: profileData.city || '',
      area: profileData.area || '',
      digital_address: profileData.digital_address || profileData.digitalAddress || '',
      residential_address: profileData.residential_address || profileData.residentialAddress || '',
      dob: profileData.dob || '',
      currency: prefs.currency || 'GHS',
      language: prefs.language || 'en',
      notificationPreference: prefs.notification_preference || prefs.notificationPreference || 'email',
      theme: prefs.theme || 'Light',
      timezone: prefs.timezone || 'Africa/Accra'
    };
  }

  static async updateProfile(formData, showSuccess, showError) {
    try {
      const updateData = {
        country: formData.country,
        city: formData.city,
        area: formData.area,
        digitalAddress: formData.digital_address
      };

      await profileService.updateProfile(updateData);

      const currentUserData = JSON.parse(localStorage.getItem('userData') || '{}');
      // Preserve the original login user ID
      const preservedId = currentUserData.id;
      const updatedUserData = {
        ...currentUserData,
        id: preservedId, // Always preserve the login user ID
        country: formData.country,
        city: formData.city,
        area: formData.area,
        digital_address: formData.digital_address,
        updated_at: new Date().toISOString()
      };

      localStorage.setItem('userData', JSON.stringify(updatedUserData));

      showSuccess('Address information updated successfully!');
      return true;
    } catch (error) {
      if (error.message.includes('Authentication required')) {
        showError('Please log in again to update your profile.');
      } else if (error.message.includes('fetch')) {
        showError('Network error. Please check your connection and try again.');
      } else {
        showError(error?.message || 'Failed to update profile. Please try again.');
      }
      return false;
    }
  }

  static async loadPreferences() {
    try {
      const prefs = await profileService.getUserPreferences();
      return prefs?.data || prefs || {};
    } catch (e) {
      return {};
    }
  }

  static async updatePreferences(formData, showSuccess, showError) {
    try {
      const payload = {
        currency: formData.currency,
        language: formData.language,
        notificationPreference: formData.notificationPreference,
        theme: formData.theme,
        timezone: formData.timezone,
      };
      await profileService.updateUserPreferences(payload);
      showSuccess('Preferences updated successfully!');
      return true;
    } catch (error) {
      if (error.message?.includes('Authentication required')) {
        showError('Please log in again to update preferences.');
      } else if (error.message?.includes('fetch')) {
        showError('Network error. Please check your connection and try again.');
      } else {
        showError(error?.message || 'Failed to update preferences. Please try again.');
      }
      return false;
    }
  }

  static getUserAccountInfo() {
    const userData = JSON.parse(localStorage.getItem('userData') || '{}');
    return {
      email: userData.email || 'Not provided',
      customerCode: userData.customer_code || 'Not provided',
      status: userData.status || 'Unknown',
      walletBalance: userData.wallet_balance || '0'
    };
  }

  static getInitialFormData() {
    return {
      fullName: '',
      phoneNumber: '',
      country: 'Ghana',
      city: '',
      area: '',
      digital_address: '',
      residential_address: '',
      dob: '',
      currency: 'GHS',
      language: 'en',
      notificationPreference: 'email',
      theme: 'Light',
      timezone: 'Africa/Accra'
    };
  }

  static formatBase64Image(base64String) {
    if (!base64String) { return ''; }

    if (base64String.startsWith('data:')) {
      return base64String;
    }

    return `data:image/png;base64,${base64String}`;
  }
}
