/**
 * Mobile Money Account List Component
 * Displays list of mobile money accounts with actions
 */

import React from 'react';

const renderMobileMoneyIcon = (provider) => {
  const providerLower = (provider || '').toLowerCase();
  if (providerLower.includes('mtn')) {
    return '📱';
  } else if (providerLower.includes('telecel') || providerLower.includes('vodafone')) {
    return '📲';
  } else if (providerLower.includes('airtel') || providerLower.includes('tigo')) {
    return '📱';
  }
  return '💳';
};

const MobileMoneyAccountList = ({
  accounts,
  onEdit,
  onDelete,
  onSetDefault,
  maxAccounts = 1,
  onAddNew,
}) => {
  const canAddMore = accounts.length < maxAccounts;

  return (
    <div data-tour="settings-payment-mobile">
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          marginBottom: '20px',
        }}
      >
        <h4 style={{ margin: 0, color: 'var(--text-primary)' }}>Mobile Money Accounts</h4>
        {canAddMore ? (
          <button
            onClick={onAddNew}
            style={{
              padding: '8px 16px',
              backgroundColor: 'var(--accent)',
              color: 'var(--text-inverse)',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
              fontSize: '14px',
              transition: 'all var(--transition-base)',
            }}
          >
            Add Mobile Money
          </button>
        ) : (
          <div
            style={{
              padding: '8px 16px',
              backgroundColor: 'var(--bg-tertiary)',
              color: 'var(--text-muted)',
              borderRadius: '6px',
              fontSize: '12px',
              fontStyle: 'italic',
            }}
          >
            Maximum {maxAccounts} account{maxAccounts > 1 ? 's' : ''} allowed
          </div>
        )}
      </div>

      {accounts.length === 0 ? (
        <div
          style={{
            textAlign: 'center',
            padding: '40px',
            backgroundColor: 'var(--bg-tertiary)',
            borderRadius: '8px',
            border: '2px dashed var(--border-secondary)',
          }}
        >
          <span
            className="material-symbols-outlined"
            style={{
              fontSize: 48,
              color: 'var(--text-muted)',
              marginBottom: '16px',
            }}
          >
            phone_android
          </span>
          <p style={{ color: 'var(--text-muted)', marginBottom: '16px' }}>
            No mobile money accounts linked yet
          </p>
          {canAddMore && (
            <button
              onClick={onAddNew}
              style={{
                padding: '10px 20px',
                backgroundColor: 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: '6px',
                cursor: 'pointer',
                transition: 'all var(--transition-base)',
              }}
            >
              Add Mobile Money
            </button>
          )}
        </div>
      ) : (
        <div style={{ display: 'grid', gap: '16px' }}>
          {accounts.map((account) => (
            <div
              key={account.id}
              style={{
                padding: '16px',
                border: '1px solid var(--border-primary)',
                borderRadius: '8px',
                backgroundColor: 'var(--card)',
              }}
            >
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                }}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span style={{ fontSize: '24px' }}>
                    {renderMobileMoneyIcon(account.provider)}
                  </span>
                  <div>
                    <p style={{ margin: 0, fontWeight: '600', color: 'var(--text-primary)', textAlign: 'left' }}>
                      {account.accountName || 'Mobile Money Account'}
                    </p>
                    <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '14px' }}>
                      {account.provider.toUpperCase()} • {(() => {
                        const num = account.phoneNumber || '';
                        if (num.length >= 6) {
                          // Mask digits 1-6
                          return '******' + num.substring(6);
                        }
                        return num;
                      })()}
                    </p>
                    <p style={{ margin: 0, color: 'var(--text-muted)', fontSize: '12px', marginTop: '4px', textAlign: 'left' }}>
                      {account.currency || 'GHS'}{account.isVerified ? ' • Verified' : ''}
                    </p>
                  </div>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>

                  {onEdit && (
                    <button
                      onClick={() => onEdit(account)}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: 'var(--bg-tertiary)',
                        color: 'var(--text-secondary)',
                        border: '1px solid var(--border-secondary)',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '12px',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px',
                        transition: 'all var(--transition-base)',
                      }}
                    >
                      <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                        edit
                      </span>
                      Edit
                    </button>
                  )}
                  {onDelete && (
                    <button
                      onClick={() => onDelete(account.id, 'momo')}
                      style={{
                        padding: '6px 12px',
                        backgroundColor: 'var(--error-bg)',
                        color: 'var(--error)',
                        border: '1px solid var(--error)',
                        borderRadius: '4px',
                        cursor: 'pointer',
                        fontSize: '12px',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '4px',
                        transition: 'all var(--transition-base)',
                      }}
                    >
                      <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
                        delete
                      </span>
                      Delete
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default MobileMoneyAccountList;



